	.SBTTL	ICOAFF; Affichage des icones ou des fichiers; ------------------------------------;--------\; AFICONE >;========/; Affiche tous les icones.; in	-; out	-; mod	D7.WAFICONE:	PUSHM.L	D0,D1,D2,D3,D4,A3,A4	CALL	OPESWDO		; efface la grande sous-fentre	CALL	CLOSWDO	LOAD.B	D3,#NOCURS	; pas de curseur	LIB	?AFCAR	CALL	AFCADRE		; dessine le nouveau cadre	CALL	USEGCI		; utilise gencar des icones	JUMP,NE	95$	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#TRAME	LOAD.L	(A3)+1,#-1	LOAD.L	(A3)+5,#-1	LOAD.W	D3,#1+8	LIB	?STRING		; dfini une trame pleine	LOAD.L	A4,(A6)+OPTDEF	; A4 <-- ^dfinitions	CLR.W	(A6)+ONBIC	CLR.W	D1		; D1 <-- compteur Y10$:	CLR.W	D0		; D0 <-- compteur X20$:	TEST.B	(A4)		; fin des dfinitions ?	JUMP,EQ	90$		; oui => 90$	COMP.B	(A4+),#CR	JUMP,NE	20$	TEST.B	(A4)		; fin des dfinitions ?	JUMP,EQ	90$		; oui => 90$	COMP.B	(A4),#'0	; est-ce bien un chiffre ?	JUMP',LO 30$		; non => laisse un "blanc"	COMP.B	(A4),#'9	; oui =>	JUMP',HI 30$	CALL	SYNICO		; D4 <-- code du caractre	CALL	AFONEICONE	; affiche l'icone30$:	INC.W	(A6)+ONBIC	INC.W	D0	COMP.W	D0,(A6)+ONBICX	JUMP,LO	20$	INC.W	D1	COMP.W	D1,(A6)+ONBICY	JUMP,LO	10$90$:	CALL	USEGCT		; utilise gencar pour textes	CALL	AFREP		; affiche le rpertoire	TCLR.B	(A6)+OFLAGS:#BLIST	TCLR.B	(A6)+OFLAGS:#BTEXT	TCLR.B	(A6)+OFLAGS:#BICONE95$:	POPM.L	D0,D1,D2,D3,D4,A3,A4	TEST.W	D7		; retour EQ/NE	RET;---------\; AFLICONE >;=========/; Affiche une liste d'icones.; in	A4.L		^numros des icones;	(A6)+OMEMLI.n	numro dernier icone trouv; out	(A6)+OLSTII.W	rang propos;	(A6)+OPTNIC.L	^liste des numros;	(A6)+OPTLIC.L	^liste des noms;	D7.W		erreur; mod	D7.WAFLICONE:	PUSHM.L	D0,D1,D2,D3,D4,A3,A4	CALL	OPESWDO		; efface la grande sous-fentre	CALL	CLOSWDO	CLR.W	(A6)+OLSTII	; montre le premier par dfaut	LOAD.B	D3,#NOCURS	; pas de curseur	LIB	?AFCAR	CALL	AFCADRE		; dessine le nouveau cadre	CALL	USEGCI		; utilise gencar des icones	JUMP,NE	95$	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#TRAME	LOAD.L	(A3)+1,#-1	LOAD.L	(A3)+5,#-1	LOAD.W	D3,#1+8	LIB	?STRING		; dfini une trame pleine	LOAD.L	(A6)+OPTNIC,A4	; mm. ^liste des numros	CLR.W	(A6)+ONBIC	CLR.W	D2		; D2 <-- rang	CLR.W	D1		; D1 <-- compteur Y10$:	CLR.W	D0		; D0 <-- compteur X20$:	COMP.B	(A4),#'0	JUMP,LO	90$	COMP.B	(A4),#'9	JUMP,HI	90$	CALL	SYNICO		; D4 <-- code du caractre	CALL	AFONEICONE	; affiche l'icone	INC.W	(A6)+ONBIC	LOAD.L	A3,#(A6)+OMEMLI	CALL	COMPARE		; comme le dernier choix ?	JUMP',NE 40$		; non => 40$	LOAD.W	(A6)+OLSTII,D2	; oui => montre celui-l40$:	EX.L	A3,A4	LIB	?SKPNAM		; A4 <-- ^numro suivant	EX.L	A4,A3	INC.W	D2		; D2 <-- rang suivant	INC.W	D0	COMP.W	D0,(A6)+ONBICX	JUMP,LO	20$	INC.W	D1	COMP.W	D1,(A6)+ONBICY	JUMP,LO	10$60$:	COMP.B	(A4),#'0	JUMP',LO 90$	COMP.B	(A4),#'9	JUMP',HI 90$	EX.L	A3,A4	LIB	?SKPNAM		; A4 <-- saute les numros pas affichs	EX.L	A4,A3	JUMP	60$90$:	LOAD.L	(A6)+OPTLIC,A4	; mm ^liste des noms	CALL	USEGCT		; utilise gencar pour textes	CALL	AFREP		; affiche le rpertoire	TCLR.B	(A6)+OFLAGS:#BLIST	TCLR.B	(A6)+OFLAGS:#BTEXT	TSET.B	(A6)+OFLAGS:#BICONE	LIB	?IFCAR		; une touche presse ?	JUMP',NE 94$		; non => 94$	CALL	FILTRE		; filtre touche souris	LOAD.W	D7,#1		; D7 <-- "erreur" spciale	COMP.B	D3,#CR		; 2x (RETURN) rapide ?	JUMP',EQ 95$		; oui => 95$	COMP.W	D3,#KEYMGP	; 2x "clic" souris rapide ?	JUMP',EQ 95$		; oui => 95$;;?	.W	LIB,?WRKEY	; remet dans fifo clavier (!)94$:	CLR.W	D7		; D7 <-- ok95$:	POPM.L	D0,D1,D2,D3,D4,A3,A4	TEST.W	D7		; retour EQ/NE	RET;-----------\; AFONEICONE >;-----------/; Affiche un caractre icone  une position X-Y.; in	D4.B	code de l'icone;	D0.W	compteur en X;	D1.W	compteur en Y; out	-; mod	D7.WAFONEICONE:	PUSHM.L	D3,D4,A3	TEST.B	D4		; icone "vide" ?	JUMP,EQ	90$		; oui => 90$	LOAD.L	A3,#(A6)+OBUDIS	LOAD.B	(A3)+0,#NUL	LOAD.B	(A3)+1,#TYPOAX	; <TYPOAX>	LOAD.W	D3,D0	MUL.WU	D3,(A6)+OLGICX	ADD.W	D3,(A6)+OMWDOX	ADD.W	D3,#MARGIC	ADD.W	D3,(A6)+OBUSTD+ODFC1X	LOAD.W	(A3)+2,D3	; <xx>	LOAD.B	(A3)+4,#NUL	LOAD.B	(A3)+5,#TYPOAY	; <TYPOAY>	LOAD.W	D3,D1	MUL.WU	D3,(A6)+OLGICY	ADD.W	D3,(A6)+OMWDOY	ADD.W	D3,#MARGIC	ADD.W	D3,(A6)+OBUSTD+ODFC1Y	LOAD.W	(A3)+6,D3	; <yy>	LOAD.B	(A3)+8,#AFTOUT	LOAD.B	(A3)+9,D4	; <code>	LOAD.B	(A3)+10,#AFNORM	LOAD.B	(A3)+11,#DRAWTRAME	LOAD.W	D3,D0	MUL.WU	D3,(A6)+OLGICX	ADD.W	D3,(A6)+OMWDOX	ADD.W	D3,#MARGIC/2	LOAD.W	(A3)+12,D3	; <xx>	LOAD.W	D3,D1	MUL.WU	D3,(A6)+OLGICY	ADD.W	D3,(A6)+OMWDOY	ADD.W	D3,#MARGIC/2	LOAD.W	(A3)+14,D3	; <yy>	LOAD.W	D3,(A6)+OLGICX	SUB.W	D3,#MARGIC	LOAD.W	(A3)+16,D3	; <dxx>	LOAD.W	D3,(A6)+OLGICY	SUB.W	D3,#MARGIC	LOAD.W	(A3)+18,D3	; <dyy>	LOAD.B	(A3)+20,#INVDOT	LOAD.W	D3,#21	TEST.B	(A6)+OFLAGS:#BAFMOD ; mode spcial ?	JUMP',BC 60$		; non => 60$	SUB.W	D3,#10		; oui => pas de pav blanc60$:	LIB	?STRING	TEST.B	(A6)+OFLAGS:#BAFMOD ; mode spcial ?	JUMP',BC 90$		; non => 90$	LOAD.W	D3,(A3)+14	SWAP.W	D3	LOAD.W	D3,(A3)+12	LOAD.W	D4,(A3)+18	SWAP.W	D4	LOAD.W	D4,(A3)+16	LOAD.W	D2,#SETDOT	LIB	?DRRECT90$:	POPM.L	D3,D4,A3	RET;--------\; AFCADRE >;--------/; Dessine le cadre dans la fentre principale.; in	-; out	-; mod	D7.WAFCADRE:	PUSHM.L	D1,D2,D3,D4,A3	TSET.B	(A6)+OFLAGS:#BAFMIN	JUMP,BS	90$	CALL	TRACADRE		; dfini la trame	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#DRAWTRAME	CLR.W	(A3)+1		; <xx>	CLR.W	(A3)+3		; <yy>	LOAD.W	(A3)+5,(A6)+OBUSTD+ODFDX ; <dxx>	LOAD.W	(A3)+7,(A6)+OMWDOY ; <dyy>	LOAD.B	(A3)+9,#SETDOT	LOAD.W	D3,#10	LIB	?STRING		; fait cadre suprieur	LOAD.W	D3,(A6)+OBUSTD+ODFDY	SUB.W	D3,(A6)+OMWDOY	LOAD.W	(A3)+3,D3	; <yy>	LOAD.W	D3,#10	LIB	?STRING		; fait cadre infrieur	LOAD.W	(A3)+3,(A6)+OMWDOY ; <yy>	LOAD.W	(A3)+5,(A6)+OMWDOX ; <dxx>	LOAD.W	D3,(A6)+OBUSTD+ODFDY	SUB.W	D3,(A6)+OMWDOY	SUB.W	D3,(A6)+OMWDOY	LOAD.W	(A3)+7,D3	; <dyy>	LOAD.W	D3,#10	LIB	?STRING		; fait cadre gauche	LOAD.W	D3,(A6)+OBUSTD+ODFDX	SUB.W	D3,(A6)+OMWDOX	LOAD.W	(A3)+1,D3	; <xx>	LOAD.W	D3,#10	LIB	?STRING		; fait cadre droite	LOAD.W	D3,(A6)+OMWDOY	; D3 <-- <yy>	DEC.W	D3	SWAP.W	D3	LOAD.W	D3,(A6)+OMWDOX	; D3 <-- <xx>	DEC.W	D3	LOAD.W	D4,(A6)+OBUSTD+ODFDY	SUB.W	D4,(A6)+OMWDOY	SUB.W	D4,(A6)+OMWDOY	; D4 <-- <dyy>	INC.W	D4	SWAP.W	D4	LOAD.W	D4,(A6)+OBUSTD+ODFDX	SUB.W	D4,(A6)+OMWDOX	SUB.W	D4,(A6)+OMWDOX	; D4 <-- <dxx>	INC.W	D4	LOAD.B	D2,#SETDOT	; D2 <-- <mode>	LOAD.B	D1,#2		; D1 <-- nb rectangles30$:	LIB	?DRRECT		; marque le cadre	SWAP.W	D3	DEC.W	D3	SWAP.W	D3	DEC.W	D3	SWAP.W	D4	ADD.W	D4,#2	SWAP.W	D4	ADD.W	D4,#2	DEC.B	D1	JUMP,NE	30$90$:	POPM.L	D1,D2,D3,D4,A3	RET;---------\; TRACADRE >;---------/; Dfini la trame pour le cadre.; in	-; out	-; mod	D7.WTRACADRE:	PUSHM.L	D3,A3	LOAD.L	A3,#(A6)+OBUDIS	LOAD.B	(A3)+0,#TRAME	LOAD.B	(A3)+1,#B'10001000	LOAD.B	(A3)+2,#B'10001000	LOAD.B	(A3)+3,#B'00100010	LOAD.B	(A3)+4,#B'00100010	LOAD.B	(A3)+5,#B'10001000	LOAD.B	(A3)+6,#B'10001000	LOAD.B	(A3)+7,#B'00100010	LOAD.B	(A3)+8,#B'00100010	COMP.B	(A6)+OMACHINE,#2 ; est-on sur un Smaky 100 ?	JUMP',NE 10$		 ; non => 10$	LOAD.B	(A3)+1,#B'10001000	LOAD.B	(A3)+2,#B'00100010	LOAD.B	(A3)+3,#B'10001000	LOAD.B	(A3)+4,#B'00100010	LOAD.B	(A3)+5,#B'10001000	LOAD.B	(A3)+6,#B'00100010	LOAD.B	(A3)+7,#B'10001000	LOAD.B	(A3)+8,#B'0010001010$:	LOAD.W	D3,#1+8	LIB	?STRING		; dfini une trame pour cadre	POPM.L	D3,A3	RET;--------\; AFTEXT  >;========/; Affiche une liste de textes.; in	A4.L		^textes; out	(A6)+OLSTII.W	rang propos;	(A6)+OPTNIC.L	^liste des textes;	(A6)+OPTLIC.L	^liste des noms;	D7.W		erreur; mod	D7.WAFTEXT:	PUSHM.L	D0,D1,D2,D3,D4,A3,A4	CLR.W	(A6)+OLSTII	; montre le premier par dfaut	LOAD.L	(A6)+OPTNIC,A4	LOAD.L	A3,A4	CALL	OPESWDO		; utilise la grande sous-fentre	CLR.W	(A6)+OSRCNN10$:	LIB	?AFTIM	.B	EOP		; efface la sous-fentre	.B	NOCURS		; plus de curseur	.B	NOROLL		; pas de scroll	.B	0	.EVEN	CALL	USEGCL		; utilise le gencar des listes	LIB	?BUCAR		; mode rapide	LIB	?AFCR		; laisse place en haut	LOAD.W	D1,(A6)+ONBLIY	; D1 <-- nb lignes	SUB.W	D1,#1+1		; laisse place en haut et bas	LOAD.W	(A6)+ONBFIY,D1	CLR.W	D2		; D2 <-- rang20$:	CLR.L	D0	LOAD.W	D0,(A6)+ONBLIX	DIV.WU	D0,#16		; D0 <-- nb textes/ligne	TEST.W	D0	JUMP',NE 25$	LOAD.W	D0,#1		; D0 <-- au moins un !25$:	LOAD.W	(A6)+ONBFIX,D030$:	CALL	AFONETEXT	; affiche un texte	INC.W	(A6)+OSRCNN	CALL	SKPNAME		; A3 <-- cherche le suivant	COMP.B	(A3),#'"	JUMP',NE 50$		; si fini => 50$	INC.W	D2		; D2 <-- rang suivant	DEC.W	D0	JUMP,NE	30$	LIB	?AFCR		; passe  la ligne suivante	DEC.W	D1	JUMP,NE	20$50$:	LIB	?NOBUCAR	LOAD.L	A3,(A6)+OPTNIC	LOAD.L	(A6)+OPTLIC,A3	; par dfaut60$:	CALL	SKPNAME		; A3 <-- cherche le suivant	COMP.B	(A3),#'"	JUMP,EQ	60$	COMP.B	(A3),#'!	JUMP',EQ 63$	COMP.B	(A3),#'|	JUMP',NE 65$63$:	CALL	SKPNAME		; A3 <-- saute "!" ou "|"	LOAD.L	(A6)+OPTLIC,A365$:	PUSH.W	D7	LIB	?NOBUCAR	; remet mode normal	TSET.B	(A6)+OFLAGS:#BLIST	TSET.B	(A6)+OFLAGS:#BTEXT	TCLR.B	(A6)+OFLAGS:#BICONE	CALL	USEGCT		; utilise gencar pour textes	CALL	CLOSWDO		; ferme la grande sous-fentre	POP.W	D7	POPM.L	D0,D1,D2,D3,D4,A3,A4	TEST.W	D7		; retour EQ/NE	RET;----------\; AFONETEXT >;----------/; Affiche un texte; in	A3.L	^texte; out	-; mod	D7.WAFONETEXT:	PUSHM.L	D3,D4,A3	INC.L	A3		; A3 <-- saute le guillemet	LOAD.B	D4,#1620$:	LOAD.B	D3,(A3+)	JUMP',EQ 40$	COMP.B	D3,#CR	JUMP',EQ 40$	COMP.B	D3,#'"	JUMP',EQ 40$	LIB	?AFCAR	DEC.B	D4	JUMP	20$40$:	LIB	?AFSPACE	DEC.B	D4	JUMP,NE	40$90$:	POPM.L	D3,D4,A3	RET;--------\; AFLIST  >;========/; Affiche une liste de fichiers selon un critre de recherche.; in	A3.L		^critre de recherche;	A4.L		^nom(s) choix par dfaut(s);	(A6)+OMEMFI.n	nom dernier fichier trouv; out	(A6)+OLSTII.W	rang propos;	D7.W		erreur; mod	D7.WAFLIST:	PUSHM.L	D0,D1,D2,D3,D4,D5,A0,A1,A3,A4,A5	LOAD.L	A0,A3		; A0 <-- ^critre	LOAD.L	A1,A4		; A1 <-- ^dfaut	CLR.W	(A6)+OLSTII	; montre le premier par dfaut	CALL	OPESWDO		; utilise la grande sous-fentre	CALL	USEGCL		; utilise le gencar des listes	CALL	INISRC		; dbut d'une recherche	JUMP,NE	60$	LOAD.L	A3,#R16"TXMEST	LIB	?AFMENU		; affiche le menu "stop"10$:	CALL	RAZSRC		; remet  zro la recherche	LIB	?AFTIM	.B	EOP		; efface la sous-fentre	.B	NOCURS		; plus de curseur	.B	NOROLL		; pas de scroll	.B	0	.EVEN	LIB	?BUCAR		; mode rapide	LIB	?AFCR		; laisse place en haut	LOAD.W	D1,(A6)+ONBLIY	; D1 <-- nb lignes	SUB.W	D1,#1+1		; laisse place en haut et bas	LOAD.W	(A6)+ONBFIY,D1	CLR.W	D2		; D2 <-- rang20$:	CLR.L	D0	LOAD.W	D0,(A6)+ONBLIX	DIV.WU	D0,#16		; D0 <-- nb fichiers/ligne	TEST.W	D0	JUMP',NE 25$	LOAD.W	D0,#1		; D0 <-- au moins un !25$:	LOAD.W	(A6)+ONBFIX,D030$:	CALL	NXTSRC		; cherche le suivant	JUMP,NE 50$		; si fini => 50$	CALL	AFFILE		; affiche fichier trouv	LOAD.L	A4,#(A6)+OMEMFI	; A4 <-- ^dernier choix	CALL	COMPARE		; comme le dernier choix ?	JUMP',NE 40$		; non => 40$	LOAD.W	(A6)+OLSTII,D2	; oui => montre celui-l40$:	INC.W	D2		; D2 <-- rang suivant	DEC.W	D0	JUMP,NE	30$	LIB	?AFCR		; passe  la ligne suivante	DEC.W	D1	JUMP,NE	20$	LIB	?NOBUCAR	LIB	?GETCURS	LIB	?AFTIM	.ASCIZ	/<AFINV>Voulez-vous voir la suite de la liste ?<AFDIR> /	.EVEN	LIB	?YESNO		; attend oui/non ...	JUMP,EQ	10$		; oui => 10$	LIB	?SETCURS	LOAD.B	D3,#EFLI	LIB	?AFCAR		; efface la question	CLR.W	D750$:	CALL	ENDSRC		; fin de la recherche60$:	PUSH.W	D7	LIB	?NOBUCAR	; remet mode normal	TSET.B	(A6)+OFLAGS:#BLIST	TCLR.B	(A6)+OFLAGS:#BTEXT	TCLR.B	(A6)+OFLAGS:#BICONE	CALL	USEGCT		; utilise gencar pour textes	CALL	CLOSWDO		; ferme la grande sous-fentre	POP.W	D7	CALL	AFMENU		; remet le bon menu	POPM.L	D0,D1,D2,D3,D4,D5,A0,A1,A3,A4,A5	TEST.W	D7		; retour EQ/NE	RET;--------\; AFFILE  >;--------/; Affiche un nom de fichier ou un nom par dfaut.; in	A3.L	^nom de fichier;	A0.L	^critre de recherche; out	-; mod	D7.WAFFILE:	PUSHM.L	D2,D3,D4,A0,A3	CLR.B	D2		; D2 <-- affiche jusqu' la fin02$:	LOAD.B	D3,(A0+)	JUMP',EQ 10$	COMP.B	D3,#CR	JUMP',EQ 10$	COMP.B	D3,#'"	JUMP',EQ 10$	COMP.B	D3,#'.	JUMP,NE	02$	COMP.B	(A0)-2,#'*	; "*." dans critre de recherche ?	JUMP',NE 10$		; non => 10$	LOAD.B	D2,#'.		; D2 <-- affiche jusqu'au "."10$:	LOAD.B	D4,#1620$:	LOAD.B	D3,(A3+)	JUMP',EQ 40$	COMP.B	D3,#CR	JUMP',EQ 40$	COMP.B	D3,#'"	JUMP',EQ 40$	COMP.B	D3,D2	JUMP',EQ 40$	LIB	?AFCAR	DEC.B	D4	JUMP	20$40$:	LIB	?AFSPACE	DEC.B	D4	JUMP,NE	40$90$:	POPM.L	D2,D3,D4,A0,A3	RET;--------\\; AFERR   >;========/; Affiche une erreur.; in	D7.W	code de l'erreur; out	-; mod	-AFERR:	PUSHM.L	D3,D7	PUSH.W	D7	CALL	USEGCL		; utilise le gencar des listes	LOAD.B	D3,#BIPERR	LIB	?BEEP	LIB	?AFTIM	.B	CR,NOCURS,AFINV,0	.EVEN	POP.W	D7	LIB	?AFERROR	; affiche l'erreur	LOAD.B	D3,#AFDIR	LIB	?AFCAR	CALL	USEGCT		; utilise gencar pour textes	CALL	GETCAR		; attend une touche ...	POPM.L	D3,D7	RET;--------\\; AFERRP  >;========/; Affiche une erreur lors de l'excution d'un programme.; in	D7.W	erreur; out	-; mod	-AFERRP:	PUSHM.L	D3,D7,A3	PUSH.W	D7	CALL	USEGCL		; utilise le gencar des listes	LOAD.B	D3,#BIPERR	LIB	?BEEP		; mauvais bruit	LIB	?AFTIM	.B	CR,NOCURS,0	.EVEN	LOAD.L	A3,#(A6)+OBUEXE	; A3 <-- ^commande excute40$:	LOAD.B	D3,(A3+)	JUMP',EQ 45$	COMP.B	D3,#CR	JUMP',EQ 45$	COMP.B	D3,#SPACE	JUMP',EQ 45$	LIB	?AFCAR		; affiche nom du programme	JUMP	40$45$:	LIB	?AFTIM	.ASCIZ	/ --<'>> <AFINV>/	.EVEN	POP.W	D7	LIB	?AFERROR	; affiche l'erreur	LOAD.B	D3,#AFDIR	LIB	?AFCAR	CALL	USEGCT		; utilise gencar pour textes	CALL	GETCAR		; attend une touche ...	POPM.L	D3,D7,A3	RET;--------\; AFSLEEP >;========/; Diminue l'intensit de l'affichage en cas d'inutilisation; prolonge.; in	-; out	-; mod	D7.WAFSLEEP:	PUSHM.L	D2,D3,D4,A3	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#TRAME	LOAD.B	(A3)+1,#B'10001000	LOAD.B	(A3)+2,#B'10001000	LOAD.B	(A3)+3,#B'00100010	LOAD.B	(A3)+4,#B'00100010	LOAD.B	(A3)+5,#B'10001000	LOAD.B	(A3)+6,#B'10001000	LOAD.B	(A3)+7,#B'00100010	LOAD.B	(A3)+8,#B'00100010	COMP.B	(A6)+OMACHINE,#2 ; est-on sur un Smaky 100 ?	JUMP',NE 10$		 ; non => 10$	LOAD.B	(A3)+1,#B'10001000	LOAD.B	(A3)+2,#B'00000000	LOAD.B	(A3)+3,#B'00100010	LOAD.B	(A3)+4,#B'00000000	LOAD.B	(A3)+5,#B'10001000	LOAD.B	(A3)+6,#B'00000000	LOAD.B	(A3)+7,#B'00100010	LOAD.B	(A3)+8,#B'0000000010$:	LOAD.W	D3,#1+8	LIB	?STRING		; dfini la trame	LIB	?GETDIM		; D4 <-- dimensions fentre	CLR.L	D3		; D3 <-- origine	LOAD.W	D2,#CLRDOT	; D2 <-- mode enlve	LIB	?DRMATRIX	; clairci toute la fentre	LIB	?AFTIM	.B	NOCURS		; plus de curseur;;?	.B	AFCCMO		; plus de flche souris	.B	0	.EVEN	TCLR.B	(A6)+OFLAGS:#BAFMIN ; faudra refaire le cadre	POPM.L	D2,D3,D4,A3	RET;----------\; AFNOSLEEP >;==========/; Rveil l'affichage.; in	-; out	-; mod	D7.WAFNOSLEEP:	LIB	?AFTIM	.B	CURS		; remet le curseur;;?	.B	AFSCMO		; remet la flche souris	.B	0	.EVEN	RET;--------\; OPESWDO >;========/; Ouvre la sous-fentre dans le cadre.; in	-; out	-; mod	D7.WOPESWDO:	PUSHM.L	D3,D4,D5	LOAD.B	D3,#NOCURS	LIB	?AFCAR		; plus de curseur	LOAD.W	D3,(A6)+OMWDOY	SWAP.W	D3	LOAD.W	D3,(A6)+OMWDOX	LOAD.W	D4,(A6)+OBUSTD+ODFDY	SUB.W	D4,(A6)+OMWDOY	SUB.W	D4,(A6)+OMWDOY	SWAP.W	D4	LOAD.W	D4,(A6)+OBUSTD+ODFDX	SUB.W	D4,(A6)+OMWDOX	SUB.W	D4,(A6)+OMWDOX	LIB	?CREWDO		; cre swdo maximale	JUMP,NE	90$	LOAD.W	(A6)+ONSWDO,D5	; mm. no swdo provisoire	LIB	?USEWDO		; utilise swdo maximale	LIB	?AFTIM	.B	EOP,0		; efface TOUTE la swdo	.EVEN	CALL	CLOSWDO		; ferme swdo maximale	ADD.W	D3,(A6)+OLGLIX	ADD.W	D3,(A6)+OLGLIX	; D3 <-- p'tites marges	SUB.W	D4,(A6)+OLGLIX	SUB.W	D4,(A6)+OLGLIX	SUB.W	D4,(A6)+OLGLIX	; D4 <-- diminue largeur	LIB	?CREWDO		; cre swdo avec marges	JUMP,NE	90$	LOAD.W	(A6)+ONSWDO,D5	; mm. no swdo dfinitive	LIB	?USEWDO		; utilise swdo avec marges	LIB	?AFTIM	.B	CR		; une ligne vide en haut	.B	CURS		; met le curseur	.B	0	.EVEN90$:	POPM.L	D3,D4,D5	RET;--------\; CLOSWDO >;========/; Ferme la sous-fentre dans le cadre.; in	-; out	-; mod	D7.WCLOSWDO:	PUSHM.L	D3,D4,D5	TEST.W	(A6)+ONSWDO	; swdo existe ?	JUMP,EQ	90$		; non => 90$	CLR.W	D5	LIB	?USEWDO		; utilise swdo principale	LOAD.W	D5,(A6)+ONSWDO	; D5 <-- no swdo  dtruire	LIB	?KILWDO		; dtruit swdo dans cadre	CLR.W	(A6)+ONSWDO90$:	POPM.L	D3,D4,D5	RET; Dtection en fonction de la position de la souris; -------------------------------------------------;--------\; DETECTE >;========/; Dtecte dans quel icone ou fichier est la souris.; in	D4.L	coordonne de la souris; out	D7.W	ok;	 D4.W	 rang;	D7.W	erreur;	 D4.W	 -1; mod	D4.L, D7.WDETECTE:	TEST.B	(A6)+OFLAGS:#BLIST	JUMP,BS	DFICHIER;	JUMP	DICONE;--------\; DICONE  >;--------/; Dtecte dans quel icone est la souris.; in	D4.L	coordonne de la souris; out	D7.W	ok;	 D4.W	 rang de l'icone;	D7.W	erreur;	 D4.W	 -1; mod	D4.L, D7.WDICONE:	PUSHM.L	D0,D3	LOAD.W	D3,D4		; D3 <-- x	SWAP.W	D4		; D4 <-- y	LOAD.W	D7,#ERDIOUT	SUB.W	D3,(A6)+OMWDOX	JUMP',LO 90$	LOAD.W	D0,(A6)+OBUSTD+ODFDX	SUB.W	D0,(A6)+OMWDOX	SUB.W	D0,(A6)+OMWDOX	COMP.W	D3,D0	JUMP',HS 90$	AND.L	D3,#H'FFFF	DIV.WU	D3,(A6)+OLGICX	SUB.W	D4,(A6)+OMWDOY	JUMP',LO 90$	LOAD.W	D0,(A6)+OBUSTD+ODFDY	SUB.W	D0,(A6)+OMWDOY	SUB.W	D0,(A6)+OMWDOY	COMP.W	D4,D0	JUMP',HS 90$	AND.L	D4,#H'FFFF	DIV.WU	D4,(A6)+OLGICY	MUL.WU	D4,(A6)+ONBICX	ADD.W	D4,D3		; D4 <-- rang de l'icone	COMP.W	D4,(A6)+ONBIC	; icone existe ?	JUMP',HS 90$		; non => 90$				; oui =>	CLR.W	D7		; D7 <-- ok90$:	TEST.W	D7		; icone trouv ?	JUMP',EQ 95$		; oui => 95$	LOAD.W	D4,#-1		; non => donne rang spcial95$:	POPM.L	D0,D3	TEST.W	D7		; retour EQ/NE	RET;---------\; DFICHIER >;---------/; Dtecte dans quel fichier est la souris.; in	D4.L	coordonne de la souris; out	D7.W	ok;	 D4.W	 rang;	D7.W	erreur;	 D4.W	 -1; mod	D4.L, D7.WDFICHIER:	PUSHM.L	D3	LOAD.W	D3,D4		; D3 <-- x	SWAP.W	D4		; D4 <-- y	LOAD.W	D7,#ERDIOUT	SUB.W	D3,(A6)+OMWDOX	JUMP',LO 90$	LOAD.W	D0,(A6)+OLGLIX	SL.W	D0,#1		; D0 <-- p'tite marge  gauche	SUB.W	D3,D0	JUMP',LO 90$	LOAD.W	D0,(A6)+OLGLIX	MUL.WU	D0,#16	AND.L	D3,#H'FFFF	DIV.WU	D3,D0	COMP.W	D3,(A6)+ONBFIX	JUMP',HS 90$	SUB.W	D4,(A6)+OMWDOY	JUMP',LO 90$	SUB.W	D4,(A6)+OLGLIY	JUMP',LO 90$	AND.L	D4,#H'FFFF	DIV.WU	D4,(A6)+OLGLIY	COMP.W	D4,(A6)+ONBFIY	JUMP',HI 90$	MUL.WU	D4,(A6)+ONBFIX	ADD.W	D4,D3		; D4 <-- rang	COMP.W	D4,(A6)+OSRCNN	; fichier dans l'cran ?	JUMP',HS 90$		; non => 90$				; oui =>	CLR.W	D7		; D7 <-- ok, trouv90$:	TEST.W	D7		; fichier trouv ?	JUMP',EQ 95$		; oui => 95$	LOAD.W	D4,#-1		; non => donne rang spcial95$:	POPM.L	D3	TEST.W	D7		; retour EQ/NE	RET; Inversion des zones dtectes; -----------------------------;--------\; INVERSE >;========/; Inverse l'icone ou le fichier choisi.; in	D4.W	rang de l'icone (si -1 => pas de dessin); out	-; mod	D7.WINVERSE:	TEST.B	(A6)+OFLAGS:#BLIST	JUMP,BS	IFICHIER;	JUMP	IICONE;--------\; IICONE  >;--------/; Inverse l'icone choisi.; in	D4.W	rang de l'icone (si -1 => pas de dessin); out	-; mod	D7.WIICONE:	PUSHM.L	D3,D4,A3	COMP.W	D4,#-1		; faut-il dessiner ?	JUMP,EQ	90$		; non => 90$				; oui =>	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#TRAME	LOAD.L	(A3)+1,#-1	LOAD.L	(A3)+5,#-1	LOAD.W	D3,#1+8	LIB	?STRING		; dfini la trame	AND.L	D4,#H'FFFF	DIV.WU	D4,(A6)+ONBICX	LOAD.W	D3,D4		; D3 <-- y	SWAP.W	D4		; D4 <-- x	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#DRAWTRAME	MUL.WU	D4,(A6)+OLGICX	ADD.W	D4,(A6)+OMWDOX	ADD.W	D4,#(MARGIC/2)+2	LOAD.W	(A3)+1,D4	; <xx>	MUL.WU	D3,(A6)+OLGICY	ADD.W	D3,(A6)+OMWDOY	ADD.W	D3,#MARGIC	ADD.W	D3,(A6)+OBUSTD+ODFC1Y	LOAD.W	(A3)+3,D3	; <yy>	LOAD.W	D3,(A6)+OLGICX	SUB.W	D3,#MARGIC+(2+2)	LOAD.W	(A3)+5,D3	; <dxx>	LOAD.W	D3,(A6)+OBUSTD+ODFC2Y	ADD.W	D3,#(MARGIC/2)-2	LOAD.W	(A3)+7,D3	; <dyy>	LOAD.B	(A3)+9,#INVDOT	; <mode>	LOAD.W	D3,#10	LIB	?STRING90$:	POPM.L	D3,D4,A3	RET;---------\; IFICHIER >;---------/; Inverse le fichier choisi.; in	D4.W	rang du fichier (si -1 => pas de dessin); out	-; mod	D7.WIFICHIER:	PUSHM.L	D0,D3,D4,A3	COMP.W	D4,#-1		; faut-il dessiner ?	JUMP,EQ	90$		; non => 90$				; oui =>	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#TRAME	LOAD.L	(A3)+1,#-1	LOAD.L	(A3)+5,#-1	LOAD.W	D3,#1+8	LIB	?STRING		; dfini la trame	AND.L	D4,#H'FFFF	DIV.WU	D4,(A6)+ONBFIX	LOAD.W	D3,D4		; D3 <-- y	SWAP.W	D4		; D4 <-- x	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#DRAWTRAME	LOAD.W	D0,(A6)+OMWDOX	ADD.W	D0,(A6)+OLGLIX	ADD.W	D0,(A6)+OLGLIX	; D0 <-- origine swdo	AND.B	D0,#B'11111000	; modulo 8 (swdo)	MUL.WU	D4,#16	MUL.WU	D4,(A6)+OLGLIX	ADD.W	D4,D0	LOAD.W	(A3)+1,D4	; <xx>	INC.W	D3	MUL.WU	D3,(A6)+OLGLIY	ADD.W	D3,(A6)+OMWDOY	LOAD.W	(A3)+3,D3	; <yy>	LOAD.W	D3,(A6)+OLGLIX	MUL.WU	D3,#16-1	LOAD.W	(A3)+5,D3	; <dxx>	LOAD.W	(A3)+7,(A6)+OLGLJY ; <dyy>	LOAD.B	(A3)+9,#INVDOT	LOAD.W	D3,#10	LIB	?STRING90$:	POPM.L	D0,D3,D4,A3	RET;--------\; AFCOMM  >;========/; Affiche la ligne de commande.; in	-; out	-; mod	-AFCOMM:	PUSHM.L	D2,D3,D4,D7,A3	LIB	?BUCAR		; mode rapide	CALL	USEGCT		; utilise le gencar des textes	LOAD.L	D3,(A6)+OPOSW	LIB	?SETCURS	LIB	?AFTIM	.B	NOCURS		; plus de curseur pendant l'affichage	.B	AFTOUT		; affiche tous les codes	.ASCIZ	/ Commande: /	.EVEN	LOAD.L	A3,#(A6)+OBUEXE	; A3 <-- ^commande	LOAD.W	D4,#ABUEXE-2	LOAD.B	D2,#1		; D2 <-- "flags" premier espace20$:	LOAD.B	D3,(A3+)	JUMP',EQ 50$	COMP.B	D3,#CR	JUMP',EQ 50$	COMP.B	D3,#CARMARK	JUMP,EQ	20$	LIB	?AFCAR	DEC.W	D4	JUMP',EQ 50$	COMP.B	D3,#SPACE	JUMP,NE	20$	DEC.B	D2		; premier espace ?	JUMP,NE	20$		; non => 20$; N'affiche rien entre les premiers <SPACE> et <CARMARK>.30$:	LOAD.B	D3,(A3+)	JUMP',EQ 50$	COMP.B	D3,#CR	JUMP',EQ 50$	COMP.B	D3,#CARMARK	JUMP,EQ	20$	JUMP	30$50$:	LOAD.B	D3,#AFNORM	LIB	?AFCAR	TEST.W	D4		; ligne toute pleine ?	JUMP',EQ 70$		; oui => 70$	LIB	?GETCURS	LOAD.L	D2,D3		; D2 <-- pos. actuelle	LOAD.B	D3,#MSPACE	LIB	?AFCAR	LOAD.B	D3,D4	INC.B	D3		; compte le marqueur "trop plein"	LIB	?AFCAR		; efface la fin de la ligne	LOAD.L	D3,D2		; D3 <-- pos. aprs "Commande"	LIB	?SETCURS	JUMP'	80$70$:	LOAD.B	D3,(A3+)	; encore qq chose  afficher ?	JUMP',EQ 80$		; non => 80$	COMP.B	D3,#CR	JUMP',EQ 80$	LOAD.B	D3,#4!2^7	LIB	?AFCODE		; indique fin ligne tronque80$:	LOAD.B	D3,#CURS	LIB	?AFCAR		; remet le curseur	LIB	?NOBUCAR	; remet mode normal	POPM.L	D2,D3,D4,D7,A3	RET;--------\; AFREP   >;========/; Affiche le rpertoire s'il existe.; in	(A6)+OBUREP.n	nom du rpertoire;	(A6)+OPOSR.L	position pour afficher;	(A6)+OLGREP.W	lg dernier rpertoire affich; out	(A6)+OLGREP.W	lg nouveau rpertoire affich; mod	-AFREP:	PUSHM.L	D2,D3,D4,D7,A3	LIB	?BUCAR		; mode rapide	CALL	USEGCT		; utilise le gencar standard	CALL	EFREP		; efface l'ancien nom	LOAD.L	D3,(A6)+OPOSR	; D3 <-- position dbut	CLR.W	D2		; D2 <-- longueur nulle	LOAD.L	A3,#(A6)+OBUREP	; A3 <-- ^rp:,#MM0:	TEST.B	(A3)		; rpertoire existe ?	JUMP',EQ 50$		; non => 50$				; oui =>	LIB	?SETCURS	LIB	?AFTIM	.B	NOCURS	.ASCIZ	/ Rpertoire = /	.EVEN	LOAD.W	D2,#14		; D2 <-- lg  / Rpertoire = /20$:	LOAD.B	D3,(A3+)	JUMP',EQ 30$	COMP.B	D3,#CR	JUMP',EQ 30$	COMP.B	D3,#':	JUMP',EQ 30$	LIB	?AFCAR	INC.W	D2		; D2 <-- un caractre de plus	JUMP	20$30$:	LIB	?AFSPACE	INC.W	D2		; D2 <-- un caractre de plus	LIB	?GETCURS	; D3 <-- pos fin repertoire50$:	LOAD.W	(A6)+OLGREP,D2	; mm. nouvelle longueur	CALL	TRACADRE	; dfini la trame du cadre	SWAP.W	D3	SUB.W	D3,(A6)+OLGC1Y	LOAD.W	D2,D3	SWAP.W	D3	LOAD.W	D4,(A6)+OLGCAX	; D4 <-- largeur d'un caractre	MUL.WU	D4,#30		; D4 <-- largeur maximale	ADD.W	D4,(A6)+OPOSR+2	; D4 <-- position extrme droite	COMP.W	D4,(A6)+OBUSTD+ODFDX ; dpasse  droite ?	JUMP',LS 60$		; non => 60$	LOAD.W	D4,(A6)+OBUSTD+ODFDX ; oui => met le maximum60$:	SUB.W	D4,D3		; D4 <-- longueur  "effacer"	SWAP.W	D4	LOAD.W	D4,(A6)+OLGCAY	; D4 <-- hauteur d'un caractre	ADD.W	D4,D2		; D4 <-- position extrme bas	COMP.W	D4,(A6)+OBUSTD+ODFDY ; dpasse en bas ?	JUMP',LS 70$		; non => 70$	LOAD.W	D4,(A6)+OBUSTD+ODFDY ; oui => met le maximum70$:	SUB.W	D4,D2		; D4 <-- hauteur  "effacer"	SWAP.W	D4	LOAD.W	D2,#SETDOT	; D2 <-- mode de dessin	LIB	?DRMATRIX	; "efface" la fin	LIB	?NOBUCAR	; remet mode normal	POPM.L	D2,D3,D4,D7,A3	RET;--------\; EFREP   >;--------/; Efface l'ancien rpertoire.; in	(A6)+OLGREP.W	lg rpertoire actuellement affich; out	-; mod	-EFREP:	PUSHM.L	D3,D7	TEST.W	(A6)+OLGREP	; lg nulle ?	JUMP',EQ 90$		; oui => 90$				; non =>	LOAD.L	D3,(A6)+OPOSR	LIB	?SETCURS	LOAD.B	D3,#MSPACE	LIB	?AFCAR	LOAD.W	D3,(A6)+OLGREP	LIB	?AFCAR90$:	POPM.L	D3,D7	RET;--------\; INIDIS  >;========/; Initialise les paramtres pour l'affichage des icones.; in	-; out	D7.W	erreur; mod	D7.WINIDIS:	PUSHM.L	D1,D2,D3,D4,D6,A4	LIB	?AFTIM	.B	TRUNC		; tronque les lignes	.B	NOCURS		; pas de curseur	.B	NOROLL		; pas de scroll	.B	NOEFLI		; n'efface pas les lignes	.B	0	.EVEN	LOAD.L	A4,#(A6)+OBUSTD	; A4 <-- ^buffer	LOAD.L	D4,#LGDIS3	LOAD.W	D3,#TYPWDO	; D3 <-- type "fentre"	LIB	?GCHDIS		; D6 <-- canal de l'cran	FOS	?RSTATUS	; lit status avec gencar stand.	JUMP,NE	90$	LOAD.W	(A6)+OLGCAX,(A4)+ODFCX	LOAD.W	(A6)+OLGCAY,(A4)+ODFCY	LOAD.W	(A6)+OLGC1Y,(A4)+ODFC1Y	LOAD.L	(A6)+ODEFGC,(A4)+ODFGCF	LOAD.W	D1,(A4)+ODFC1Y	ADD.W	D1,(A4)+ODFC2Y	SR.W	D1,#1		; D1 <-- (C1Y+C2Y)/2	SUB.W	D1,(A4)+ODFC2Y	; D1 <-- (C1Y+C2Y)/2 - C2Y	CALL	USEGCI		; utilise gencar des icones	JUMP,NE	90$	LOAD.L	D4,#LGDIS3	LOAD.W	D3,#TYPWDO	; D3 <-- type "fentre"	FOS	?RSTATUS	; lit status avec gencar icone	JUMP,NE	90$	CLR.L	D3	LOAD.W	D3,(A4)+ODFDX	; D3 <-- largeur fentre	LOAD.W	D4,(A4)+ODFC1X	ADD.W	D4,(A4)+ODFC2X	; D4 <-- largeur icone	ADD.W	D4,#MARGIC*2	LOAD.W	(A6)+OLGICX,D4	DIV.WU	D3,D4		; D3 <-- nb icones en X	LOAD.L	D2,D3	SWAP.W	D2		; D2 <-- reste pour marge	SR.W	D4,#2		; D4 <-- 1/4 largeur icone	COMP.W	D2,D4		; reste assez pour marge ?	JUMP',HS 20$		; oui => 20$	DEC.W	D3		; non => un icone de moins20$:	LOAD.W	(A6)+ONBICX,D3	MUL.WU	D3,(A6)+OLGICX	; D3 <-- largeur pour icones	SUB.W	D3,(A6)+OBUSTD+ODFDX	NEG.W	D3		; D3 <-- reste pour 2 marges	SR.W	D3,#1		; D3 <-- reste pour 1 marge	AND.B	D3,#B'11111000	; doit tre modulo 8	LOAD.W	(A6)+OMWDOX,D3	CLR.L	D3	LOAD.W	D3,(A4)+ODFDY	; D3 <-- hauteur fentre	LOAD.W	D4,(A4)+ODFC1Y	ADD.W	D4,(A4)+ODFC2Y	; D4 <-- hauteur icone	ADD.W	D4,#MARGIC*2	LOAD.W	(A6)+OLGICY,D4	DIV.WU	D3,D4		; D3 <-- nb icones en Y	LOAD.L	D2,D3	SWAP.W	D2		; D2 <-- reste pour marges	SR.W	D2,#1		; D2 <-- reste pour marge	COMP.W	D2,(A6)+OLGCAY	; reste assez pour marge ?	JUMP',HS 40$		; oui => 40$	DEC.W	D3		; non => un icone de moins40$:	LOAD.W	(A6)+ONBICY,D3	MUL.WU	D3,(A6)+OLGICY	; D3 <-- hauteur pour icones	SUB.W	D3,(A6)+OBUSTD+ODFDY	NEG.W	D3		; D3 <-- reste pour 2 marges	SR.W	D3,#1		; D3 <-- reste pour 1 marge	AND.B	D3,#B'11111110	; doit tre modulo 2	LOAD.W	(A6)+OMWDOY,D3	LOAD.W	D7,#ERDIOUT	TEST.W	(A6)+ONBICX	JUMP,EQ	90$	TEST.W	(A6)+ONBICY	JUMP,EQ	90$	CALL	USEGCL		; utilise gencar des listes	LOAD.L	D4,#LGDIS3	LOAD.W	D3,#TYPWDO	; D3 <-- type "fentre"	FOS	?RSTATUS	; lit status avec gencar listes	JUMP,NE	90$	LOAD.W	(A6)+OLGLIX,(A4)+ODFCX	LOAD.W	(A6)+OLGLIY,(A4)+ODFCY	LOAD.W	D4,(A4)+ODFC1Y	ADD.W	D4,(A4)+ODFC2Y	LOAD.W	(A6)+OLGLJY,D4	CLR.L	D4	LOAD.W	D4,(A4)+ODFDX	SUB.W	D4,(A6)+OMWDOX	SUB.W	D4,(A6)+OMWDOX	; D4 <-- largeur fentre	DIV.WU	D4,(A4)+ODFCX	; D4 <-- nb car. dans fentre	SUB.W	D4,#2+1		; D4 <-- enlve marges gauche et droite	LOAD.W	(A6)+ONBLIX,D4	CLR.L	D4	LOAD.W	D4,(A4)+ODFDY	SUB.W	D4,(A6)+OMWDOY	SUB.W	D4,(A6)+OMWDOY	; D4 <-- hauteur fentre	DIV.WU	D4,(A4)+ODFCY	; D4 <-- nb car. dans fentre	LOAD.W	(A6)+ONBLIY,D4	CALL	USEGCI		; utilise gencar des icones	JUMP,NE	90$	LOAD.L	D4,#LGDIS3	LOAD.W	D3,#TYPWDO	; D3 <-- type "fentre"	FOS	?RSTATUS	; lit status avec gencar icones	JUMP,NE	90$	CALL	USEGCL		; utilise gencar des listes	JUMP,NE	90$	LOAD.W	(A6)+OPOSWX,(A6)+OMWDOX	LOAD.W	D4,(A6)+OLGCAX	MUL.WU	D4,#ABUEXE+11	; nb car pour  / Commande: .../	SUB.W	D4,(A6)+OBUSTD+ODFDX	JUMP',HS 70$	NEG.W	D4	SR.W	D4,#1		; 1/2  gauche et 1/2  droite	LOAD.W	(A6)+OPOSWX,D470$:	LOAD.W	D4,(A6)+OMWDOY	SR.W	D4,#1	ADD.W	D4,D1		; centrage prci	DEC.W	D4		; perfectionniste, va !	LOAD.W	(A6)+OPOSWY,D4	LOAD.W	(A6)+OPOSRX,(A6)+OPOSWX	LOAD.W	D4,(A6)+OMWDOY	SR.W	D4,#1	SUB.W	D4,(A6)+OBUSTD+ODFDY	NEG.W	D4	ADD.W	D4,D1		; centrage prci	INC.W	D4	LOAD.W	(A6)+OPOSRY,D4	CLR.W	D7		; D7 <-- ok90$:	POPM.L	D1,D2,D3,D4,D6,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; USEGCI  >;========/; Utilise le gnrateur de caractres pour les icones.; in	-; out	D7.W	erreur; mod	D7.WUSEGCI:	PUSHM.L	D3,D4,D5,A3	LOAD.L	A3,(A6)+OPTDEF	; A3 <-- ^nom gencar "fsctt"	LIB	?SYNGC		; D3,D4,D5 <-- fst	JUMP',NE 90$	LOAD.L	A3,#(A6)+OBUDIS	LOAD.B	(A3)+0,#LOADGC	LOAD.B	(A3)+1,D3	LOAD.B	(A3)+2,D4	LOAD.B	(A3)+3,D5	LOAD.B	(A3)+4,#USEGC	LOAD.B	(A3)+5,D3	LOAD.B	(A3)+6,D4	LOAD.B	(A3)+7,D5	LOAD.W	D3,#4+4	LIB	?STRING90$:	POPM.L	D3,D4,D5,A3	TEST.W	D7		; retour EQ/NE	RET;--------\; KILGCI  >;========/; Libre le gnrateur de caractres des icones.; in	-; out	-; mod	-KILGCI:	PUSHM.L	D3,D4,D5,D7,A3	LOAD.L	A3,(A6)+OPTDEF	; A3 <-- ^nom gencar "fsctt"	LIB	?SYNGC		; D3,D4,D5 <-- fst	JUMP',NE 90$	LOAD.L	A3,#(A6)+OBUDIS	LOAD.B	(A3)+0,#KILLGC	LOAD.B	(A3)+1,D3	LOAD.B	(A3)+2,D4	LOAD.B	(A3)+3,D5	LOAD.W	D3,#4	LIB	?STRING90$:	POPM.L	D3,D4,D5,D7,A3	RET;--------\; USEGCL  >;========/; Utilise le gnrateur de caractres pour les listes.; in	-; out	-; mod	D7.WUSEGCL:	PUSHM.L	D3,D4,D5,A3	LOAD.L	A3,(A6)+OPTDEF	; A3 <-- ^2x nom gencar "fsctt"	LIB	?SKPNAM		; A3 <-- ^2me nom	JUMP',NE 50$	LIB	?SYNGC		; D3,D4,D5 <-- fst	JUMP',NE 50$	LOAD.L	A3,#(A6)+OBUDIS	LOAD.B	(A3)+0,#LOADGC	LOAD.B	(A3)+1,D3	LOAD.B	(A3)+2,D4	LOAD.B	(A3)+3,D5	LOAD.B	(A3)+4,#USEGC	LOAD.B	(A3)+5,D3	LOAD.B	(A3)+6,D4	LOAD.B	(A3)+7,D5	LOAD.W	D3,#4+4	LIB	?STRING	JUMP',EQ 90$50$:	CALL	USEGCT		; si erreur => utilise gencar textes90$:	POPM.L	D3,D4,D5,A3	RET;--------\; KILGCL  >;========/; Libre le gnrateur de caractres des listes.; in	-; out	-; mod	-KILGCL:	PUSHM.L	D3,D4,D5,D7,A3	LOAD.L	A3,(A6)+OPTDEF	; A3 <-- ^2x nom gencar "fsctt"	LIB	?SKPNAM		; A3 <-- ^2me nom	JUMP',NE 90$	LIB	?SYNGC		; D3,D4,D5 <-- fst	JUMP',NE 90$	LOAD.L	A3,#(A6)+OBUDIS	LOAD.B	(A3)+0,#KILLGC	LOAD.B	(A3)+1,D3	LOAD.B	(A3)+2,D4	LOAD.B	(A3)+3,D5	LOAD.W	D3,#4	LIB	?STRING90$:	POPM.L	D3,D4,D5,D7,A3	RET;--------\; USEGCT  >;========/; Utilise le gnrateur de caractres pour le texte.; in	-; out	-; mod	-USEGCT:	PUSHM.L	D3,D7,A3	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#LOADGC	LOAD.L	(A3)+1,(A6)+ODEFGC	LOAD.B	(A3)+4,#USEGC	LOAD.L	(A3)+5,(A6)+ODEFGC	LOAD.W	D3,#4+4	LIB	?STRING	POPM.L	D3,D7,A3	RET	.END